import pickle
import os
from datetime import datetime, timedelta

class Cache:
    def __init__(self, cache_dir):
        self.cache_dir = cache_dir

    def _get_cache_file(self, key):
        return f"{key}.pickle"

    def get(self, key):
        cache_file = self._get_cache_file(key)
        if os.path.exists(cache_file):
            with open(cache_file, "rb") as f:
                data, timestamp = pickle.load(f)
            if datetime.now() - timedelta(seconds=timestamp) < datetime.now():
                return data
        return None

    def set(self, key, value, expire_in=None):
        cache_file = self._get_cache_file(key)
        with open(cache_file, "wb") as f:
            timestamp = int(datetime.now().timestamp())
            if expire_in is not None:
                timestamp += expire_in.total_seconds()
            pickle.dump((value, timestamp), f)

    def delete(self, key):
        cache_file = self._get_cache_file(key)
        if os.path.exists(cache_file):
            os.remove(cache_file)


class CacheSystem:
    def __init__(self, cache_dir):
        self.cache = Cache(cache_dir)

    def get(self, key):
        return self.cache.get(key)

    def set(self, key, value, expire_in=None):
        self.cache.set(key, value, expire_in)

    def delete(self, key):
        self.cache.delete(key)


# Example usage
cache_system = CacheSystem("api_cache")

